INSERT INTO public.hardware_component VALUES (18, NULL, 'Generic Modulating Valve', NULL, NULL, NULL, 'DRAFT', 'Generic modulating (proportional) control valve with analog position feedback, open/closed end-position feedback, and analog setpoint. Use for cooling, HVAC, and process flow control valves. Source: Klippan IO-list Y01.', NULL, '2026-03-09 20:50:41.515', '2026-03-09 20:50:41.515', NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (19, NULL, 'Generic VFD Pump', NULL, NULL, NULL, 'DRAFT', 'Generic variable-frequency drive (VFD) controlled pump with running and fault feedback, start/stop commands, and analog speed setpoint. Common for cooling water circulation, seawater, freshwater, and HVAC pumps. Source: Klippan IO-list M01.', NULL, '2026-03-09 20:50:41.515', '2026-03-09 20:50:41.515', 'FB_MotorCtrlStarterVFD', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (24, NULL, 'Propulsion Motor', NULL, NULL, NULL, 'DRAFT', 'Shaft motor sensors and VMS control interface', NULL, '2026-03-10 09:27:13.159', '2026-03-10 09:27:13.159', 'FB_PropControl_rev4', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (32, NULL, 'DC Shore Connection Panel', NULL, NULL, NULL, 'DRAFT', 'Hardwired DC shore connection panel signals: intake status feedback, local control, sequence monitoring, MCB status, synchronisation, precharge and direct sync control outputs.', NULL, '2026-03-11 10:52:21.312', '2026-03-11 10:52:21.312', NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (33, NULL, 'DC Main Switchboard Panel', NULL, NULL, NULL, 'DRAFT', 'Hardwired DC main switchboard signals: isolation monitoring, main and precharge contactor control and feedback.', NULL, '2026-03-11 10:54:04.885', '2026-03-11 10:54:04.885', NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (34, NULL, 'Hydraulic Ramp/Gate System', NULL, NULL, NULL, 'DRAFT', 'Hardwired ramp and gate hydraulic system: wheelhouse command inputs (ramp up/down/float, lock hooks, gate open/close), gate position feedback, and solenoid valve outputs.', NULL, '2026-03-11 10:54:12.751', '2026-03-11 10:54:12.751', NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (36, NULL, 'AC Main Switchboard Panel', NULL, NULL, NULL, 'DRAFT', 'AC MSB hardwired signals: grid circuit breaker feedback (Q1 AFT, Q2 FWD, Q5), genset CB feedback, remote mode, insulation faults, and switching outputs.', NULL, '2026-03-11 11:00:18.814', '2026-03-11 11:00:18.814', NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (37, NULL, 'Emergency Stop Collection Panel', NULL, NULL, NULL, 'DRAFT', 'Hardwired emergency stop and backup switch collection panel (851-A01): battery, genset, shore and microgrid e-stops.', NULL, '2026-03-11 11:00:18.814', '2026-03-11 11:00:18.814', NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (38, NULL, 'Hydraulic Central Sensors', NULL, NULL, NULL, 'DRAFT', 'Shared hydraulic system sensors and controls: tank level (analog+switch), oil pressure, oil temperature (analog+switch), filter indication, and wheelhouse e-stop.', NULL, '2026-03-11 11:00:18.814', '2026-03-11 11:00:18.814', NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (39, NULL, 'Battery Room Environment', NULL, NULL, NULL, 'DRAFT', 'Battery room monitoring: pressure and temperature sensors, common alarm and gas alarm inputs.', NULL, '2026-03-11 11:00:18.814', '2026-03-11 11:00:18.814', NULL, NULL, NULL) ON CONFLICT DO NOTHING;
