INSERT INTO public.hardware_component VALUES (35, NULL, 'Hydraulic HPU VFD', NULL, NULL, NULL, 'DRAFT', 'Hardwired hydraulic power unit VFD drive: start, reset, speed reference output and fault alarm input.', NULL, '2026-03-11 10:54:20.4', '2026-03-11 10:54:20.4', 'FB_MotorCtrlStarterVFD', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (9, NULL, 'MIC MKII Power Meter', 'MIC', 'MKII', NULL, 'ACTIVE', 'MIC MKII three-phase power meter — all electrical measurements via Modbus RTU (34 signals per meter instance: per-phase and system totals for power, reactive power, apparent power, power factor, voltage, and current).', NULL, '2026-03-09 19:50:19.296', '2026-03-09 19:50:19.296', NULL, NULL, 'MODBUS_RTU') ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (3, NULL, 'Editron Converter FW11 DCDC', 'Editron', 'FW11 DCDC', NULL, 'ACTIVE', 'Editron DC/DC converter (CAN bus). Derived from 866-U01:1 in IO list 25432-852.', NULL, '2026-03-09 10:44:12.752', '2026-03-09 10:44:12.752', 'Editron_Converter_FW11_DCDC', NULL, 'CANOPEN') ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (4, NULL, 'Editron Converter FW11 MC', 'Editron', 'FW11 MC', NULL, 'ACTIVE', 'Editron motor controller (CAN bus). Derived from 861-U01 in IO list 25432-852.', NULL, '2026-03-09 10:49:29.033', '2026-03-09 10:49:29.033', 'Editron_Converter_FW11_MC', NULL, 'CANOPEN') ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (5, NULL, 'Editron Converter FW11 uG AFE', 'Editron', 'FW11 uG AFE', NULL, 'ACTIVE', 'Editron microgrid AFE converter (CAN bus). Derived from 875-U01 in IO list 25432-852.', NULL, '2026-03-09 10:49:34.963', '2026-03-09 10:49:34.963', 'Editron_Converter_FW11_uG_AFE_Rev2', NULL, 'CANOPEN') ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (7, NULL, 'EST Battery String BMS', 'EST', 'Octopus BMS', NULL, 'ACTIVE', 'EST battery string BMS — per-string data and alarm status via Modbus TCP. Template covers the main StringData block (22 signals) plus StringCtrl_Alarm_flags (29 INTERNAL bits) and StringCtrl_Error_code (2 signals). Total: 53 signals.', NULL, '2026-03-09 19:50:19.296', '2026-03-09 19:50:19.296', 'FB_BatteryPack_EST_V2_0_0', NULL, 'MODBUS_TCP') ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (8, NULL, 'Diesel Genset', NULL, 'Diesel', NULL, 'ACTIVE', 'Diesel generator set — main operational data via Modbus RTU (23 signals). ECU alarm sub-groups (ECU_Alarms_1..15) are separate instances in the Excel and not included in this template.', NULL, '2026-03-09 19:50:19.296', '2026-03-09 19:50:19.296', 'FB_ModbusDiesel', NULL, 'MODBUS_RTU') ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (14, NULL, 'Generic On/Off Pump', NULL, NULL, NULL, 'DRAFT', 'Generic fixed-speed on/off pump. Start DO and running DI feedback. Applicable to any simple pump controlled by a contactor or starter. Source: Tesya IO-list 722-M01.', NULL, '2026-03-09 20:31:12.13', '2026-03-09 20:31:12.13', 'FB_PumpCTRL', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (15, NULL, 'Generic Actuated Valve', NULL, NULL, NULL, 'DRAFT', 'Generic motorized actuated valve. Open DO, close DO, opened position DI, closed position DI. Standard 4-signal pattern for butterfly and ball valves. Source: Tesya IO-list 721-3.', NULL, '2026-03-09 20:31:12.134', '2026-03-09 20:31:12.134', 'FB_ValveAlarmAndStatus', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (17, NULL, 'Generic IEC Contactor Panel', NULL, NULL, NULL, 'ACTIVE', 'Generic hardwired contactor panel: 4 digital inputs (status/feedback) and 2 digital outputs (control commands). Used for any contactor or switching panel with IEC hardwired signals.', NULL, '2026-03-09 20:50:41.515', '2026-03-09 20:50:41.515', 'FB_MotorCtrlStarter', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (40, NULL, 'Diesel Generator Sensors', NULL, NULL, NULL, 'DRAFT', 'Physical diesel generator sensors: D-end and N-end bearing temperatures, and control cabinet speed reference.', NULL, '2026-03-11 11:00:18.814', '2026-03-11 11:00:18.814', NULL, NULL, NULL) ON CONFLICT DO NOTHING;
