INSERT INTO public.hardware_component VALUES (42, NULL, '3-Phase Shore Temperature Monitor', NULL, NULL, NULL, 'DRAFT', 'Three-phase shore connection cable temperature monitoring: L1, L2, L3 temperature inputs.', NULL, '2026-03-11 11:00:18.814', '2026-03-11 11:00:18.814', NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (43, NULL, 'Propulsion Kongsberg Interface', NULL, NULL, NULL, 'DRAFT', 'Kongsberg DP/joystick interface signals per propulsion axis: steering command reference, start-up interlock, and hydraulic pump stopped output.', NULL, '2026-03-11 11:00:18.814', '2026-03-11 11:00:18.814', NULL, NULL, NULL) ON CONFLICT DO NOTHING;
