INSERT INTO public.hardware_component VALUES (29, NULL, 'Kreisel BMS String (Debug PCAN)', 'Kreisel Electric', 'Battery BMS', NULL, 'DRAFT', 'Kreisel Electric battery string — per-string data on the debug PCAN bus. Instantiate once per BMS node (01/05/09/13/17/21/25/29). CAN ID offset per node: +0=01, +1=05, +2=09, +3=13, +4=17, +5=21, +6=25, +7=29. SlowDataMpex (0x190) uses mux (page index byte).', NULL, '2026-03-10 20:11:23.724', '2026-03-10 20:11:23.724', 'Kreisel_BMS_Comm', 529, 'CANBUS') ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (11, NULL, 'EoDev Hydrogen Fuel Cell', 'EoDev', 'FC Module', NULL, 'ACTIVE', 'EoDev hydrogen fuel cell module. Hardwired ignition DO and AO power request, analog sensors and Modbus RTU data. Covers H2 pressure, cooling temps, bus voltages, breaker states and fault levels. Source: Tesya IO-list 861-G01.', NULL, '2026-03-09 20:31:12.106', '2026-03-09 20:31:12.106', NULL, NULL, 'CANBUS') ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (12, NULL, 'Deutronic DCDC Converter', 'Deutronic', 'DCDC', NULL, 'ACTIVE', 'Deutronic DC/DC converter. AO setpoints for output current, max input current, min input voltage, temperature and output voltage. AI readbacks of setpoints and actuals. DI status: active error, warning, running, communication fault. Source: Tesya IO-list 866-U04.', NULL, '2026-03-09 20:31:12.115', '2026-03-09 20:31:12.115', NULL, NULL, 'CANBUS') ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (13, NULL, 'VESC Hydraulic Pump Drive', NULL, 'VESC Drive', NULL, 'DRAFT', 'VESC-compatible hydraulic pump motor drive. Speed reference AO, analog feedback (actual RPM, duty cycle, input voltage, AC/DC current, controller and motor temperature, throttle) and 21 discrete fault and limit status bits. Source: Tesya IO-list 639-U01.', NULL, '2026-03-09 20:31:12.123', '2026-03-09 20:31:12.123', NULL, NULL, 'CANBUS') ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (30, NULL, 'Kreisel BMS ESS Master (Debug PCAN)', 'Kreisel Electric', 'Battery BMS', NULL, 'DRAFT', 'Kreisel Electric ESS master controller — single-instance messages on the debug PCAN bus. Covers FKT handshake, ESS master state, config, and charge PID (muxed).', NULL, '2026-03-10 20:11:23.737', '2026-03-10 20:11:23.737', 'FB_Kreisel_BMS', 405, 'CANBUS') ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (10, NULL, 'Kreisel Electric BMS', 'Kreisel Electric', 'Battery BMS', NULL, 'ACTIVE', 'Kreisel Electric battery BMS. Monitoring and control via Modbus RTU and hardwired DI/AO. Covers SOC, range, state requests, isolation, cell voltages and temperatures. Source: Tesya IO-list 866-BMS 01.', NULL, '2026-03-09 20:31:12.066', '2026-03-09 20:31:12.066', 'FB_Kreisel_BMS', 546, 'CANBUS') ON CONFLICT DO NOTHING;
INSERT INTO public.hardware_component VALUES (16, NULL, 'ABB Shore Charger', 'ABB', 'ACS880 / PCS100', NULL, 'ACTIVE', 'ABB shore power charger / grid-side converter. 20 Modbus TCP register signals (control words, setpoints, measurements, fault/warning/limit words) plus 7 hardwired DI from the converter cabinet. Source: Klippan IO-list A02.1.', NULL, '2026-03-09 20:50:41.515', '2026-03-09 20:50:41.515', 'FB_ShoreAC', NULL, 'MODBUS_TCP') ON CONFLICT DO NOTHING;
